/* ---------- COUNTERS + REVEAL ---------- */
function runCount(node) {
  var target = parseInt(node.getAttribute("data-count"), 10) || 0,
    suf = node.getAttribute("data-suffix") || "";
  if (node.getAttribute("data-done")) return;
  node.setAttribute("data-done", "1");
  if (RM) {
    node.textContent = target.toLocaleString("en-US") + suf;
    return;
  }
  var start = null,
    dur = 1400;
  function step(ts) {
    if (start === null) start = ts;
    var p = Math.min((ts - start) / dur, 1),
      e = 1 - Math.pow(1 - p, 3);
    node.textContent = Math.floor(e * target).toLocaleString("en-US") + suf;
    if (p < 1) requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
}
function revealIn(scope) {
  if (!scope) return;
  var r = scope.querySelectorAll(".rv");
  for (var i = 0; i < r.length; i++) r[i].classList.add("in");
  var c = scope.querySelectorAll("[data-count]");
  for (var j = 0; j < c.length; j++) runCount(c[j]);
}

/* ---------- ROUTER ---------- */
var navBusy = false;
function _swapPage(page) {
  var target = el("page-" + page) || el("page-home");
  var pages = document.querySelectorAll(".page");
  for (var i = 0; i < pages.length; i++) pages[i].classList.remove("active");
  target.classList.add("active");
  var navPage = page === "project-detail" ? "projects" : page;
  var links = document.querySelectorAll(".nav-a");
  for (var k = 0; k < links.length; k++)
    links[k].classList.toggle(
      "active",
      links[k].getAttribute("data-nav") === navPage,
    );
  document.body.setAttribute("data-theme", target.getAttribute("data-theme") || page);
  window.scrollTo({ top: 0, behavior: "auto" });
  revealIn(target);
  apply3D();
}
function nav(page, skip) {
  var m = el("mob");
  if (m) m.classList.remove("open");
  var w = el("wipe");
  if (RM || skip || !w) {
    _swapPage(page);
    return;
  }
  if (navBusy) return;
  navBusy = true;
  w.classList.remove("reveal");
  void w.offsetWidth;
  w.classList.add("cover");
  setTimeout(function () {
    _swapPage(page);
    w.classList.remove("cover");
    void w.offsetWidth;
    w.classList.add("reveal");
    setTimeout(function () {
      w.classList.remove("reveal");
      navBusy = false;
    }, 520);
  }, 430);
}
function onScroll() {
  var n = el("nav");
  if (n) n.classList.toggle("scrolled", window.scrollY > 24);
}

/* ---------- CONTACT ---------- */
function sendContact() {
  var n = (el("c-name") || {}).value || "",
    e = (el("c-email") || {}).value || "",
    m = (el("c-msg") || {}).value || "";
  var note = document.querySelector("#page-contact .cnote");
  if (!n.trim() || !e.trim()) {
    if (note) {
      note.textContent = "Please add your name and email.";
      note.style.color = "var(--pink)";
    }
    return;
  }
  if (note) {
    note.textContent = "Sending...";
    note.style.color = "var(--faint)";
  }
  postLead("Yêu cầu tư vấn — " + ((el("c-company") || {}).value || n), {
    Ten: n,
    ChucVu: (el("c-role") || {}).value || "",
    Cong_ty: (el("c-company") || {}).value || "",
    Email: e,
    Dich_vu: (el("c-service") || {}).value || "",
    Mo_ta: m,
  })
    .then(function (r) {
      if (note) {
        note.textContent =
          r.mode === "sent"
            ? "Sent — thank you! We will be in touch shortly."
            : "Opening your email app to send your message...";
        note.style.color = "var(--pink)";
      }
      var mm = el("c-msg");
      if (mm && r.mode === "sent") mm.value = "";
    })
    .catch(function () {
      if (note) {
        note.textContent =
          "Could not send — please email joliequynh@otb-agency.com.";
        note.style.color = "var(--pink)";
      }
    });
}

/* ---------- 3D PRODUCT VIEWER ---------- */
var pv = {
  ready: false,
  renderer: null,
  scene: null,
  cam: null,
  mesh: null,
  raf: null,
  drag: false,
  lx: 0,
  ly: 0,
  rx: 0,
  ry: 0,
  zoom: 5,
};
function makeShape(kind, color) {
  var geo;
  if (kind === "knot") geo = new THREE.TorusKnotGeometry(1, 0.34, 120, 16);
  else if (kind === "ico") geo = new THREE.IcosahedronGeometry(1.5, 0);
  else if (kind === "gift") geo = new THREE.BoxGeometry(2, 2, 2);
  else if (kind === "dodeca") geo = new THREE.DodecahedronGeometry(1.6, 0);
  else geo = new THREE.SphereGeometry(1.5, 48, 48);
  var mat = new THREE.MeshStandardMaterial({
    color: color,
    roughness: 0.35,
    metalness: 0.25,
  });
  return new THREE.Mesh(geo, mat);
}
var PRODPHOTO = ["gift", "about", "seminar", "hero"];
function makePhotoCard(key) {
  var edge = new THREE.MeshBasicMaterial({ color: 0x0a1f44 });
  var src = typeof IMG !== "undefined" && IMG[key] ? IMG[key] : null;
  if (!src) return new THREE.Mesh(new THREE.BoxGeometry(3, 2, 0.12), edge);
  var tex = new THREE.TextureLoader().load(src);
  var photo = new THREE.MeshBasicMaterial({ map: tex });
  return new THREE.Mesh(new THREE.BoxGeometry(3.1, 2.0, 0.12), [
    edge,
    edge,
    edge,
    edge,
    photo,
    photo,
  ]);
}
function pvSize() {
  if (!pv.renderer) return;
  var s = el("pv-stage");
  var w = s.clientWidth || 400,
    h = s.clientHeight || 340;
  pv.renderer.setSize(w, h);
  pv.cam.aspect = w / h;
  pv.cam.updateProjectionMatrix();
}
function ensurePV() {
  if (pv.ready || typeof THREE === "undefined") return pv.ready;
  var stage = el("pv-stage");
  if (!stage) return false;
  try {
    pv.renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    pv.renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
    stage.appendChild(pv.renderer.domElement);
    pv.scene = new THREE.Scene();
    pv.cam = new THREE.PerspectiveCamera(45, 1.2, 0.1, 100);
    pv.cam.position.z = pv.zoom;
    pv.scene.add(new THREE.AmbientLight(0xffffff, 0.7));
    var d = new THREE.DirectionalLight(0xffffff, 0.9);
    d.position.set(4, 5, 6);
    pv.scene.add(d);
    var p = new THREE.PointLight(0xff5c8a, 0.6);
    p.position.set(-4, -2, 3);
    pv.scene.add(p);
    var c = pv.renderer.domElement;
    c.addEventListener("pointerdown", function (e) {
      pv.drag = true;
      pv.lx = e.clientX;
      pv.ly = e.clientY;
    });
    window.addEventListener("pointerup", function () {
      pv.drag = false;
    });
    window.addEventListener("pointermove", function (e) {
      if (!pv.drag || !pv.mesh) return;
      pv.ry += (e.clientX - pv.lx) * 0.01;
      pv.rx += (e.clientY - pv.ly) * 0.01;
      pv.lx = e.clientX;
      pv.ly = e.clientY;
    });
    c.addEventListener(
      "wheel",
      function (e) {
        e.preventDefault();
        pv.zoom = Math.max(
          3,
          Math.min(9, pv.zoom + (e.deltaY > 0 ? 0.4 : -0.4)),
        );
        pv.cam.position.z = pv.zoom;
      },
      { passive: false },
    );
    pv.ready = true;
  } catch (err) {
    pv.ready = false;
  }
  return pv.ready;
}
function pvLoop() {
  pv.raf = requestAnimationFrame(pvLoop);
  if (!pv.mesh) return;
  if (!pv.drag && !RM) pv.ry += 0.005;
  pv.mesh.rotation.x = pv.rx;
  pv.mesh.rotation.y = pv.ry;
  pv.renderer.render(pv.scene, pv.cam);
}
var pvImgs = [],
  pvIdx = 0,
  pvTimer = null,
  pvBound = false;
function openProduct(i) {
  var p = PRODUCTS[i];
  if (!p) return;
  el("pv-title").textContent = L(p.t, p.t_en);
  el("pv-desc").textContent = L(p.d, p.d_en);
  el("pv-points").innerHTML = (p.pts || [])
    .map(function (x, k) {
      return "<li>" + esc(L(x, (p.pts_en || [])[k])) + "</li>";
    })
    .join("");
  pvImgs = (
    p.gallery && p.gallery.length ? p.gallery : [p.photo || "hero"]
  ).map(galSrc);
  pvIdx = 0;
  pvDots();
  pvRender();
  if (!pvBound) {
    pvBind();
    pvBound = true;
  }
  el("pv").classList.add("open");
  pvAuto();
}
function pvRender() {
  var im = el("pv-img");
  if (!im || !pvImgs.length) return;
  im.src = pvImgs[pvIdx];
  var d = el("pv-dots");
  if (d) {
    var ch = d.children;
    for (var k = 0; k < ch.length; k++) {
      ch[k].className = "ss-dot" + (k === pvIdx ? " on" : "");
    }
  }
}
function pvDots() {
  var d = el("pv-dots");
  if (!d) return;
  var html = "";
  for (var k = 0; k < pvImgs.length; k++) {
    html +=
      '<button class="ss-dot' +
      (k === 0 ? " on" : "") +
      '" onclick="pvGo(' +
      k +
      ')" aria-label="Slide ' +
      (k + 1) +
      '"></button>';
  }
  d.innerHTML = html;
  var show = el("pv-show");
  var multi = pvImgs.length > 1;
  if (show) show.classList.toggle("single", !multi);
  d.style.display = multi ? "" : "none";
}
function pvGo(k) {
  if (!pvImgs.length) return;
  pvIdx = (k + pvImgs.length) % pvImgs.length;
  pvRender();
  pvAuto();
}
function pvSlide(dir) {
  pvGo(pvIdx + dir);
}
function pvAuto() {
  clearTimeout(pvTimer);
  if (RM || pvImgs.length < 2 || !el("pv").classList.contains("open")) return;
  pvTimer = setTimeout(function () {
    pvSlide(1);
  }, 4200);
}
function pvBind() {
  var sh = el("pv-show");
  if (sh) {
    var x0 = null;
    sh.addEventListener(
      "touchstart",
      function (e) {
        x0 = e.touches[0].clientX;
      },
      { passive: true },
    );
    sh.addEventListener("touchend", function (e) {
      if (x0 == null) return;
      var dx = e.changedTouches[0].clientX - x0;
      if (Math.abs(dx) > 40) pvSlide(dx < 0 ? 1 : -1);
      x0 = null;
    });
  }
  window.addEventListener("keydown", function (e) {
    if (!el("pv").classList.contains("open")) return;
    if (e.key === "ArrowLeft") pvSlide(-1);
    else if (e.key === "ArrowRight") pvSlide(1);
    else if (e.key === "Escape") closeProduct();
  });
}
function closeProduct() {
  el("pv").classList.remove("open");
  clearTimeout(pvTimer);
}

/* ---------- CHAT ---------- */
var chatOpen = false,
  chatBusy = false,
  greeted = false,
  chatHistory = [];
function toggleChat() {
  chatOpen = !chatOpen;
  el("chat").classList.toggle("open", chatOpen);
  if (chatOpen && !greeted) {
    greeted = true;
    greet();
  }
  if (chatOpen)
    setTimeout(function () {
      el("chat-input").focus();
    }, 300);
}
function addMsg(role, text) {
  var b = el("chat-body");
  var d = document.createElement("div");
  d.className = "msg " + (role === "user" ? "me" : "bot");
  d.textContent = text;
  b.appendChild(d);
  b.scrollTop = b.scrollHeight;
  return d;
}
function greet() {
  addMsg(
    "bot",
    L(
      "Xin chào! Mình là trợ lý của OTB. Bạn có thể hỏi về dịch vụ, mạng lưới bác sĩ, hay cách bắt đầu hợp tác — mình sẵn sàng giúp.",
      "Hi! I'm OTB's assistant. Ask me about our solutions, doctor network, or how to get started — happy to help.",
    ),
  );
  var b = el("chat-body");
  var w = document.createElement("div");
  w.className = "chips";
  var qs = L(
    "OTB làm gì?|Mạng lưới bác sĩ lớn cỡ nào?|Đặt lịch tư vấn thế nào?",
    "What does OTB do?|How big is your doctor network?|How do I book a consultation?",
  ).split("|");
  qs.forEach(function (q) {
    var c = document.createElement("div");
    c.className = "chip-s";
    c.textContent = q;
    c.onclick = function () {
      el("chat-input").value = q;
      chatSend();
    };
    w.appendChild(c);
  });
  b.appendChild(w);
  b.scrollTop = b.scrollHeight;
}
function claudeFetch(payload) {
  return fetch("/api/chat", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
  })
    .then(function (r) {
      if (!r.ok) throw 0;
      return r.json();
    })
    .catch(function () {
      return fetch("api/concierge.php", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      }).then(function (r) {
        if (!r.ok) throw 0;
        return r.json();
      });
    });
}
function chatSend() {
  if (chatBusy) return;
  var inp = el("chat-input");
  var q = (inp.value || "").trim();
  if (!q) return;
  var chips = el("chat-body").querySelector(".chips");
  if (chips) chips.remove();
  addMsg("user", q);
  inp.value = "";
  chatHistory.push({ role: "user", content: q });
  chatBusy = true;
  var b = el("chat-body");
  var t = document.createElement("div");
  t.className = "typing";
  t.innerHTML = "<span></span><span></span><span></span>";
  b.appendChild(t);
  b.scrollTop = b.scrollHeight;
  claudeFetch({ system: KB, messages: chatHistory })
    .then(function (data) {
      t.remove();
      var txt = "";
      if (data && data.content)
        for (var i = 0; i < data.content.length; i++) {
          if (data.content[i].type === "text") txt += data.content[i].text;
        }
      if (!txt)
        txt = L(
          "Cảm ơn bạn! Để được phản hồi nhanh nhất, vui lòng gọi 0939 945 867 hoặc email joliequynh@otb-agency.com.",
          "Thanks for your message! For the fastest reply, call 0939 945 867 or email joliequynh@otb-agency.com.",
        );
      addMsg("bot", txt);
      chatHistory.push({ role: "assistant", content: txt });
      chatBusy = false;
    })
    .catch(function () {
      t.remove();
      addMsg(
        "bot",
        L(
          "Hiện mình chưa kết nối được trợ lý. Vui lòng gọi 0939 945 867 hoặc email joliequynh@otb-agency.com để đội ngũ OTB hỗ trợ bạn nhé.",
          "I can't reach the assistant right now. Please call 0939 945 867 or email joliequynh@otb-agency.com and our team will help you.",
        ),
      );
      chatBusy = false;
    });
}

/* ---------- HERO TILT ---------- */
function heroTilt() {
  var ph = el("hero-photo");
  if (!ph || RM) return;
  var hv = ph.parentElement;
  hv.addEventListener("pointermove", function (e) {
    var r = hv.getBoundingClientRect();
    var px = (e.clientX - r.left) / r.width - 0.5,
      py = (e.clientY - r.top) / r.height - 0.5;
    ph.style.transform =
      "rotateY(" +
      (px * 8).toFixed(2) +
      "deg) rotateX(" +
      (-py * 8).toFixed(2) +
      "deg)";
  });
  hv.addEventListener("pointerleave", function () {
    ph.style.transform = "";
  });
}

