function filterHCP(k, btn) {
  var t = el("spec-tags");
  if (t) {
    var b = t.querySelectorAll("button");
    for (var i = 0; i < b.length; i++) b[i].classList.remove("on");
  }
  if (btn) btn.classList.add("on");
  renderRoster(k);
}

/* ---- booking ---- */
function openBooking(spec) {
  if (BK_FORM_HTML && el("bk-body")) el("bk-body").innerHTML = BK_FORM_HTML;
  var ss = el("bk-service");
  if (ss)
    ss.innerHTML = HCP_SERVICES.map(function (s) {
      return "<option>" + esc(L(s.n_vi, s.n)) + "</option>";
    }).join("");
  var sp = el("bk-spec");
  if (sp) {
    sp.innerHTML =
      '<option value="">' +
      esc(L("Tất cả chuyên khoa", "Any specialty")) +
      "</option>" +
      SPECIALTIES.map(function (s) {
        return (
          '<option value="' + s.k + '">' + esc(L(s.vn, s.en)) + "</option>"
        );
      }).join("");
    if (spec) sp.value = spec;
  }
  var d = el("bk-date");
  if (d) {
    try {
      d.min = new Date().toISOString().slice(0, 10);
    } catch (e) {}
  }
  el("bk").classList.add("open");
}
function closeBooking() {
  el("bk").classList.remove("open");
}
function postLead(subject, data) {
  if (FORM_ENDPOINT) {
    return fetch(FORM_ENDPOINT, {
      method: "POST",
      headers: {
        Accept: "application/json",
        "Content-Type": "application/json",
      },
      body: JSON.stringify(Object.assign({ _subject: subject }, data)),
    }).then(function (r) {
      if (!r.ok) throw 0;
      return { mode: "sent" };
    });
  }
  var body = Object.keys(data)
    .map(function (k) {
      return k + ": " + (data[k] || "-");
    })
    .join("\r\n");
  window.location.href =
    "mailto:joliequynh@otb-agency.com?subject=" +
    encodeURIComponent(subject) +
    "&body=" +
    encodeURIComponent(body);
  return Promise.resolve({ mode: "mailto" });
}
function submitBooking() {
  if ((el("bk-hp") || {}).value) {
    closeBooking();
    return;
  }
  var name = (el("bk-name") || {}).value || "",
    co = (el("bk-co") || {}).value || "",
    email = (el("bk-email") || {}).value || "";
  var note = el("bk-note");
  if (!name.trim() || !co.trim() || !email.trim()) {
    if (note) {
      note.textContent = "Please fill in your name, company and email.";
      note.style.color = "var(--pink)";
    }
    return;
  }
  var data = {
    Name: name,
    Company: co,
    Email: email,
    Phone: (el("bk-phone") || {}).value,
    Industry: (el("bk-industry") || {}).value,
    Service: (el("bk-service") || {}).value,
    Specialty: (el("bk-spec") || {}).options
      ? el("bk-spec").options[el("bk-spec").selectedIndex].text
      : "",
    PreferredDate: (el("bk-date") || {}).value,
    Format: (el("bk-format") || {}).value,
    Budget: (el("bk-budget") || {}).value,
    Needs: (el("bk-msg") || {}).value,
  };
  if (note) {
    note.textContent = "Sending...";
    note.style.color = "var(--faint)";
  }
  postLead("HCP booking request — " + co, data)
    .then(function (r) {
      var b = el("bk-body");
      if (b)
        b.innerHTML =
          '<div class="bk-success"><div class="bk-tick">&#10003;</div><h3>Request received</h3><p>' +
          (r.mode === "sent"
            ? "Thank you — our team will reply within one business day."
            : "Your email app is opening with the request filled in. Send it and we'll reply within one business day.") +
          '</p><button class="btn btn-pri" onclick="closeBooking()">Done</button></div>';
    })
    .catch(function () {
      if (note) {
        note.textContent =
          "Could not send right now — please email joliequynh@otb-agency.com.";
        note.style.color = "var(--pink)";
      }
    });
}

function apply3D() {
  if (RM) return;
  var sel =
    ".prod,.svc-card,.work-card,.feat,.value-card,.news-card,.hcp-card,.hcp-svc,.hcp-w,.hcp-group,.net-chip,.hphoto";
  var nodes = document.querySelectorAll(sel);
  for (var i = 0; i < nodes.length; i++) {
    (function (c) {
      if (c.dataset.t3d || c.id === "hero-photo") return;
      c.dataset.t3d = "1";
      c.classList.add("tilt3d");
      c.addEventListener("pointermove", function (e) {
        var r = c.getBoundingClientRect();
        var px = (e.clientX - r.left) / r.width - 0.5,
          py = (e.clientY - r.top) / r.height - 0.5;
        c.style.transform =
          "perspective(900px) rotateY(" +
          (px * 9).toFixed(2) +
          "deg) rotateX(" +
          (-py * 9).toFixed(2) +
          "deg) translateZ(6px)";
      });
      c.addEventListener("pointerleave", function () {
        c.style.transform = "";
      });
    })(nodes[i]);
  }
}

function bi(vi, en) {
  return (
    '<span class="t-vi">' +
    esc(vi) +
    '</span><span class="t-en">' +
    esc(en || vi) +
    "</span>"
  );
}
function L(vi, en) {
  return document.body.getAttribute("data-lang") === "en" ? en : vi;
}
(function () {
  var tt = null,
    sb = null;
  function onScr() {
    tt = tt || document.getElementById("to-top");
    sb = sb || document.getElementById("scrollbar");
    var h = document.documentElement;
    var max = h.scrollHeight - h.clientHeight || 1;
    var y = window.scrollY || h.scrollTop || 0;
    if (sb) sb.style.width = Math.min(1, y / max) * 100 + "%";
    if (tt) tt.classList.toggle("show", y > 600);
  }
  window.addEventListener("scroll", onScr, { passive: true });
  window.addEventListener("resize", onScr, { passive: true });
  document.addEventListener("DOMContentLoaded", onScr);
})();
function splitHeroWords() {
  var hs = document.querySelectorAll(".phero h1");
  for (var i = 0; i < hs.length; i++) {
    var h = hs[i];
    if (h.getAttribute("data-split")) continue;
    h.setAttribute("data-split", "1");
    var spans = h.querySelectorAll(".t-vi,.t-en");
    if (!spans.length) spans = [h];
    for (var j = 0; j < spans.length; j++) {
      var sp = spans[j],
        words = (sp.textContent || "").split(" "),
        html = "",
        wi = 0;
      for (var k = 0; k < words.length; k++) {
        if (!words[k]) continue;
        html +=
          '<span class="w" style="--wi:' +
          wi++ +
          '">' +
          esc(words[k]) +
          "</span> ";
      }
      sp.innerHTML = html;
    }
  }
}
document.addEventListener("DOMContentLoaded", splitHeroWords);
(function () {
  /* magnetic buttons */
  var fine = false;
  try {
    fine = window.matchMedia && matchMedia("(pointer:fine)").matches;
  } catch (e) {}
  if (!fine || RM) return;
  function mv(e) {
    var r = this.getBoundingClientRect();
    var x = (e.clientX - r.left) / r.width - 0.5,
      y = (e.clientY - r.top) / r.height - 0.5;
    this.style.transform =
      "translate(" + (x * 9).toFixed(1) + "px," + (y * 7).toFixed(1) + "px)";
  }
  function lv() {
    this.style.transform = "";
  }
  document.addEventListener("pointerover", function (e) {
    var t = e.target;
    var b = t && t.closest ? t.closest(".btn,.lang-btn") : null;
    if (!b || b.__m) return;
    b.__m = 1;
    b.addEventListener("pointermove", mv);
    b.addEventListener("pointerleave", lv);
  });
})();
(function () {
  /* cursor glow */
  var fine = false;
  try {
    fine = window.matchMedia && matchMedia("(pointer:fine)").matches;
  } catch (e) {}
  if (!fine || RM) return;
  var g = null,
    on = false;
  document.addEventListener(
    "pointermove",
    function (e) {
      g = g || document.getElementById("glow");
      if (!g) return;
      if (!on) {
        on = true;
        g.style.opacity = "1";
      }
      g.style.transform =
        "translate3d(" +
        e.clientX +
        "px," +
        e.clientY +
        "px,0) translate(-50%,-50%)";
    },
    { passive: true },
  );
})();
(function () {
  /* hero spotlight */
  var ph = document.querySelector("#page-home .phero");
  if (!ph) return;
  ph.addEventListener(
    "pointermove",
    function (e) {
      var r = ph.getBoundingClientRect();
      ph.style.setProperty(
        "--sx",
        ((e.clientX - r.left) / r.width) * 100 + "%",
      );
      ph.style.setProperty(
        "--sy",
        ((e.clientY - r.top) / r.height) * 100 + "%",
      );
    },
    { passive: true },
  );
})();
(function () {
  /* scroll-driven 3D tilt of hero photo (Aceternity container-scroll feel) */
  if (RM) return;
  var t = document.getElementById("hero-tilt");
  if (!t) return;
  function upd() {
    var ph =
      document.querySelector("#page-home.active") ||
      document.getElementById("page-home");
    if (
      !ph ||
      (ph.classList.contains("active") === false &&
        document.querySelector(".page.active") !== ph)
    ) {
      t.style.transform = "";
      return;
    }
    var y = window.scrollY || 0;
    var p = Math.max(0, Math.min(1, y / 520));
    var rotX = (1 - p) * 18,
      sc = 0.96 + p * 0.04,
      ty = (1 - p) * -14;
    t.style.transform =
      "perspective(1100px) rotateX(" +
      rotX.toFixed(2) +
      "deg) scale(" +
      sc.toFixed(3) +
      ") translateY(" +
      ty.toFixed(1) +
      "px)";
  }
  window.addEventListener("scroll", upd, { passive: true });
  window.addEventListener("resize", upd, { passive: true });
  document.addEventListener("DOMContentLoaded", upd);
  upd();
})();
(function () {
  /* Three.js floating navy/pink shapes behind hero */
  if (RM || typeof THREE === "undefined") return;
  var cv = document.getElementById("hero3d");
  if (!cv) return;
  var rndr,
    scene,
    cam,
    grp,
    raf,
    mx = 0,
    my = 0,
    W,
    H,
    run = true;
  try {
    rndr = new THREE.WebGLRenderer({
      canvas: cv,
      alpha: true,
      antialias: true,
    });
    rndr.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
    scene = new THREE.Scene();
    cam = new THREE.PerspectiveCamera(55, 1, 0.1, 100);
    cam.position.z = 15;
    grp = new THREE.Group();
    scene.add(grp);
    var pink = 0xff5c8a,
      blue = 0x5a86ff,
      white = 0xbfd0ff;
    var geos = [
      new THREE.IcosahedronGeometry(1.5, 0),
      new THREE.TorusGeometry(1.1, 0.4, 16, 40),
      new THREE.DodecahedronGeometry(1.4, 0),
      new THREE.OctahedronGeometry(1.5, 0),
    ];
    var cols = [pink, blue, white, pink];
    var items = [];
    for (var i = 0; i < 11; i++) {
      var g = geos[i % geos.length];
      var m = new THREE.MeshStandardMaterial({
        color: cols[i % cols.length],
        roughness: 0.35,
        metalness: 0.25,
        transparent: true,
        opacity: 0.82,
        flatShading: true,
      });
      var mesh = new THREE.Mesh(g, m);
      mesh.position.set(
        (Math.random() - 0.5) * 22,
        (Math.random() - 0.5) * 13,
        (Math.random() - 0.5) * 8 - 2,
      );
      var sc = 0.5 + Math.random() * 0.9;
      mesh.scale.setScalar(sc);
      mesh.userData = {
        rx: (Math.random() - 0.5) * 0.006,
        ry: (Math.random() - 0.5) * 0.006,
        fy: Math.random() * 6.28,
        sp: 0.4 + Math.random() * 0.5,
        base: mesh.position.y,
      };
      grp.add(mesh);
      items.push(mesh);
    }
    scene.add(new THREE.AmbientLight(0xffffff, 0.65));
    var d1 = new THREE.DirectionalLight(0xffffff, 1.1);
    d1.position.set(6, 8, 10);
    scene.add(d1);
    var p1 = new THREE.PointLight(pink, 1.3, 60);
    p1.position.set(-10, 6, 8);
    scene.add(p1);
    function size() {
      var ph = document.querySelector("#page-home .phero");
      if (!ph) return;
      W = ph.clientWidth;
      H = ph.clientHeight;
      rndr.setSize(W, H, false);
      cam.aspect = W / H;
      cam.updateProjectionMatrix();
    }
    window.addEventListener("resize", size);
    size();
    document.querySelector("#page-home .phero").addEventListener(
      "pointermove",
      function (e) {
        var r = this.getBoundingClientRect();
        mx = (e.clientX - r.left) / r.width - 0.5;
        my = (e.clientY - r.top) / r.height - 0.5;
      },
      { passive: true },
    );
    var t0 = Date.now();
    function loop() {
      if (!run) return;
      raf = requestAnimationFrame(loop);
      var t = (Date.now() - t0) / 1000;
      for (var i = 0; i < items.length; i++) {
        var o = items[i];
        o.rotation.x += o.userData.rx;
        o.rotation.y += o.userData.ry;
        o.position.y =
          o.userData.base + Math.sin(t * o.userData.sp + o.userData.fy) * 0.6;
      }
      grp.rotation.y += (mx * 0.5 - grp.rotation.y) * 0.04;
      grp.rotation.x += (my * 0.35 - grp.rotation.x) * 0.04;
      rndr.render(scene, cam);
    }
    loop();
    // pause when home not active / tab hidden (saves battery)
    document.addEventListener("visibilitychange", function () {
      run = !document.hidden;
      if (run && !raf) {
        loop();
      } else {
        cancelAnimationFrame(raf);
        raf = 0;
      }
    });
  } catch (e) {
    if (cv) cv.style.display = "none";
  }
})();
function setLang(lang) {
  var b = document.body;
  lang = lang === "en" ? "en" : "vi";
  b.setAttribute("data-lang", lang);
  var en = lang === "en";
  var l = document.getElementById("lang-label");
  if (l) l.textContent = en ? "VI" : "EN";
  var lm = document.getElementById("lang-label-m");
  if (lm) lm.textContent = en ? "VI" : "EN";
  var ns = document.querySelectorAll("[data-ph-vi]");
  for (var i = 0; i < ns.length; i++) {
    ns[i].placeholder = en
      ? ns[i].getAttribute("data-ph-en") || ""
      : ns[i].getAttribute("data-ph-vi") || "";
  }
  var op = document.querySelectorAll(".lang-switch .ls-opt");
  for (var k = 0; k < op.length; k++) {
    op[k].classList.toggle("active", op[k].getAttribute("data-l") === lang);
  }
}
function toggleLang() {
  setLang(document.body.getAttribute("data-lang") === "en" ? "vi" : "en");
}
document.addEventListener("DOMContentLoaded", function () {
  try {
    setLang(document.body.getAttribute("data-lang") || "vi");
  } catch (e) {}
});

